import React, { useState, useEffect } from 'react';
import { Upload, Play, X } from 'lucide-react';
import './VideoUploadGrid.css';

const VideoUploadGrid = () => {
  // Load saved videos from localStorage on component mount
  const [videos, setVideos] = useState(() => {
    const savedVideos = localStorage.getItem('uploadedVideos');
    if (savedVideos) {
      return JSON.parse(savedVideos);
    }
    return [
      { id: 1, thumbnail: null, title: '', module: '' },
      { id: 2, thumbnail: null, title: '', module: '' },
      { id: 3, thumbnail: null, title: '', module: '' },
      { id: 4, thumbnail: null, title: '', module: '' }
    ];
  });

  // Save videos to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem('uploadedVideos', JSON.stringify(videos));
  }, [videos]);

  const modules = ['Super Admin', 'School Admin', 'Guide', 'Student', 'Parent'];

  const handleVideoUpload = (id, event) => {
    const file = event.target.files[0];
    if (file && file.type.startsWith('video/')) {
      generateVideoThumbnail(file, id);
    } else {
      alert('Please select a valid video file');
    }
  };

  const generateVideoThumbnail = (file, videoId) => {
    const video = document.createElement('video');
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    video.preload = 'metadata';
    video.src = URL.createObjectURL(file);

    video.onloadedmetadata = () => {
      // Set canvas dimensions to match video
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      // Seek to 1 second (or first frame if shorter)
      video.currentTime = Math.min(1, video.duration / 10);
    };

    video.onseeked = () => {
      // Draw the video frame to canvas
      context.drawImage(video, 0, 0, canvas.width, canvas.height);

      // Convert canvas to data URL
      const thumbnailUrl = canvas.toDataURL('image/jpeg', 0.8);

      // Update state with thumbnail
      setVideos(prev => prev.map(video => 
        video.id === videoId 
          ? { ...video, thumbnail: thumbnailUrl, fileName: file.name }
          : video
      ));

      // Clean up object URL
      URL.revokeObjectURL(video.src);
    };

    video.onerror = () => {
      console.error('Error loading video');
      URL.revokeObjectURL(video.src);
    };
  };

  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [previewVideo, setPreviewVideo] = useState(null);

  const clearAllData = () => {
    setShowConfirmDialog(true);
  };

  const confirmClearData = () => {
    localStorage.removeItem('uploadedVideos');
    setVideos([
      { id: 1, thumbnail: null, title: '', module: '' },
      { id: 2, thumbnail: null, title: '', module: '' },
      { id: 3, thumbnail: null, title: '', module: '' },
      { id: 4, thumbnail: null, title: '', module: '' }
    ]);
    setShowConfirmDialog(false);
  };

  const cancelClearData = () => {
    setShowConfirmDialog(false);
  };

  const openVideoPreview = (video) => {
    setPreviewVideo(video);
  };

  const closeVideoPreview = () => {
    setPreviewVideo(null);
  };

  const handleModuleChange = (id, module) => {
    setVideos(prev => prev.map(video => 
      video.id === id 
        ? { ...video, module }
        : video
    ));
  };

  const handleTitleChange = (id, title) => {
    setVideos(prev => prev.map(video => 
      video.id === id 
        ? { ...video, title }
        : video
    ));
  };

  const removeVideo = (id) => {
    setVideos(prev => prev.map(video => 
      video.id === id 
        ? { ...video, thumbnail: null, title: '', module: '' }
        : video
    ));
  };

  // Store the actual video file for preview
  const videoFiles = useRef({});

  const storeVideoFile = (id, file) => {
    videoFiles.current[id] = file;
  };

  return (
    <div className="video-upload-grid">
      <div className="grid-header">
        <h2>Video Upload Grid</h2>
        <button onClick={clearAllData} className="clear-btn">
          Clear All Data
        </button>
      </div>
      <div className="grid-container">
        {videos.map((video) => (
          <div key={video.id} className="video-card">
            <div className="video-upload-area">
              {video.thumbnail ? (
                <div className="video-preview">
                  <img src={video.thumbnail} alt="Video thumbnail" className="thumbnail" />
                  <div className="video-overlay">
                    <Play size={32} className="play-icon" />
                    <button 
                      className="remove-btn"
                      onClick={() => removeVideo(video.id)}
                      aria-label="Remove video"
                    >
                      <X size={20} />
                    </button>
                  </div>
                </div>
              ) : (
                <label className="upload-label">
                  <input
                    type="file"
                    accept="video/*"
                    onChange={(e) => handleVideoUpload(video.id, e)}
                    className="file-input"
                  />
                  <div className="upload-content">
                    <Upload size={48} className="upload-icon" />
                    <p className="upload-text">Upload Video</p>
                    <p className="upload-subtext">Click to browse or drag and drop</p>
                  </div>
                </label>
              )}
            </div>

            <div className="video-info">
              <input
                type="text"
                placeholder="Video title..."
                value={video.title}
                onChange={(e) => handleTitleChange(video.id, e.target.value)}
                className="video-title-input"
              />

              <div className="module-selector">
                <label className="module-label">Module:</label>
                <select
                  value={video.module}
                  onChange={(e) => handleModuleChange(video.id, e.target.value)}
                  className="module-select"
                >
                  <option value="">Select module...</option>
                  {modules.map((module) => (
                    <option key={module} value={module}>
                      {module}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>
        ))}
      </div>

      {showConfirmDialog && (
        <div className="confirm-dialog-overlay">
          <div className="confirm-dialog">
            <h3>Confirm Clear Data</h3>
            <p>Are you sure you want to clear all uploaded videos? This action cannot be undone.</p>
            <div className="confirm-dialog-buttons">
              <button onClick={cancelClearData} className="cancel-btn">
                Cancel
              </button>
              <button onClick={confirmClearData} className="confirm-btn">
                Clear All
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default VideoUploadGrid;
